import pytest
import requests

def test_non_admin_delete_onboarding_task_returns_403(admin_token, viewer_token, base_url, create_onboarding_task):
    task_id = create_onboarding_task(admin_token)
    headers = {"Authorization": f"Bearer {viewer_token}"}

    response = requests.delete(
        f"{base_url}/api/onboarding-tasks/{task_id}",
        headers=headers,
        timeout=10
    )

    assert response.status_code == 403, (
        f"Expected 403, got {response.status_code}: {response.text}"
    )
